   218→func (a *dashboardSqlAccess) migrateDashboards(ctx context.Context, orgId int64, opts MigrateOptions, stream resourcepb.BulkStore_BulkProcessClient) (*BlobStoreInfo, error) {
   219→	query := &DashboardQuery{
   220→		OrgID:         orgId,
   221→		Limit:         100000000,
   222→		GetHistory:    opts.WithHistory, // include history
   223→		AllowFallback: true,             // allow fallback to dashboard table during migration
   224→		Order:         "ASC",            // oldest first
   225→	}
   226→
   227→	blobs := &BlobStoreInfo{}
   228→	sql, err := a.sql(ctx)
   229→	if err != nil {
   230→		return blobs, err
   231→	}
   232→
   233→	opts.Progress(-1, "migrating dashboards...")
   234→	rows, err := a.getRows(ctx, sql, query)
   235→	if rows != nil {
   236→		defer func() {
   237→			_ = rows.Close()
   238→		}()
   239→	}
   240→	if err != nil {
   241→		return blobs, err
   242→	}
   243→
   244→	large := opts.LargeObjects
   245→
   246→	// Now send each dashboard
   247→	for i := 1; rows.Next(); i++ {
   248→		dash := rows.row.Dash
   249→		if dash.APIVersion == "" {
   250→			dash.APIVersion = fmt.Sprintf("%s/v0alpha1", dashboard.GROUP)
   251→		}
   252→		dash.SetNamespace(opts.Namespace)
   253→		dash.SetResourceVersion("") // it will be filled in by the backend
   254→
   255→		body, err := json.Marshal(dash)
   256→		if err != nil {
   257→			err = fmt.Errorf("error reading json from: %s // %w", rows.row.Dash.Name, err)
   258→			return blobs, err
   259→		}
   260→
   261→		req := &resourcepb.BulkRequest{
   262→			Key: &resourcepb.ResourceKey{
   263→				Namespace: opts.Namespace,
   264→				Group:     dashboard.GROUP,
   265→				Resource:  dashboard.DASHBOARD_RESOURCE,
   266→				Name:      rows.Name(),
   267→			},
   268→			Value:  body,
   269→			Folder: rows.row.FolderUID,
   270→			Action: resourcepb.BulkRequest_ADDED,
   271→		}
   272→		if dash.Generation > 1 {
   273→			req.Action = resourcepb.BulkRequest_MODIFIED
   274→		} else if dash.Generation < 0 {
   275→			req.Action = resourcepb.BulkRequest_DELETED
   276→		}
   277→
   278→		// With large object support
   279→		if large != nil && len(body) > large.Threshold() {
   280→			obj, err := utils.MetaAccessor(dash)
   281→			if err != nil {
   282→				return blobs, err
   283→			}
   284→
   285→			opts.Progress(i, fmt.Sprintf("[v:%d] %s Large object (%d)", dash.Generation, dash.Name, len(body)))
   286→			err = large.Deconstruct(ctx, req.Key, opts.BlobStore, obj, req.Value)
   287→			if err != nil {
   288→				return blobs, err
   289→			}
   290→
   291→			// The smaller version (most of spec removed)
   292→			req.Value, err = json.Marshal(dash)
   293→			if err != nil {
   294→				return blobs, err
   295→			}
   296→			blobs.Count++
   297→			blobs.Size += int64(len(body))
   298→		}
   299→
   300→		opts.Progress(i, fmt.Sprintf("[v:%2d] %s (size:%d / %d|%d)", dash.Generation, dash.Name, len(req.Value), i, rows.count))
   301→
   302→		err = stream.Send(req)
   303→		if err != nil {
   304→			if errors.Is(err, io.EOF) {
   305→				opts.Progress(i, fmt.Sprintf("stream EOF/cancelled. index=%d", i))
   306→				err = nil
   307→			}
   308→			return blobs, err
   309→		}
   310→	}
   311→
   312→	if len(rows.rejected) > 0 {
   313→		for _, row := range rows.rejected {
   314→			id := row.Dash.Labels[utils.LabelKeyDeprecatedInternalID]
   315→			a.log.Warn("rejected dashboard",
   316→				"namespace", opts.Namespace,
   317→				"dashboard", row.Dash.Name,
   318→				"uid", row.Dash.UID,
   319→				"id", id,
   320→				"version", row.Dash.Generation,
   321→				"stackId", opts.StackID,
   322→			)
   323→			opts.Progress(-2, fmt.Sprintf("rejected: id:%s, uid:%s", id, row.Dash.Name))
   324→		}
   325→	}
   326→
   327→	if rows.Error() != nil {
   328→		return blobs, rows.Error()
   329→	}
   330→
   331→	opts.Progress(-2, fmt.Sprintf("finished dashboards... (%d)", rows.count))
   332→	return blobs, err
   333→}
