     4→// These functions handle the common logic for migrating datasource references from
     5→// string names/UIDs to structured reference objects with uid, type, and apiVersion.
     6→
     7→// GetDataSourceRef creates a datasource reference object with uid, type and optional apiVersion
     8→func GetDataSourceRef(ds *DataSourceInfo) map[string]interface{} {
     9→	if ds == nil {
    10→		return nil
    11→	}
    12→	ref := map[string]interface{}{
    13→		"uid":  ds.UID,
    14→		"type": ds.Type,
    15→	}
    16→	if ds.APIVersion != "" {
    17→		ref["apiVersion"] = ds.APIVersion
    18→	}
    19→	return ref
    20→}
    21→
    22→// GetDefaultDSInstanceSettings returns the default datasource if one exists
    23→func GetDefaultDSInstanceSettings(datasources []DataSourceInfo) *DataSourceInfo {
    24→	for _, ds := range datasources {
    25→		if ds.Default {
    26→			return &DataSourceInfo{
    27→				UID:        ds.UID,
    28→				Type:       ds.Type,
    29→				Name:       ds.Name,
    30→				APIVersion: ds.APIVersion,
    31→			}
    32→		}
    33→	}
    34→	return nil
    35→}
    36→
    37→// isDataSourceRef checks if the object is a valid DataSourceRef (has uid or type)
    38→// Matches the frontend isDataSourceRef function in datasource.ts
    39→func isDataSourceRef(ref interface{}) bool {
    40→	dsRef, ok := ref.(map[string]interface{})
    41→	if !ok {
    42→		return false
    43→	}
    44→
    45→	hasUID := false
    46→	if uid, exists := dsRef["uid"]; exists {
    47→		if uidStr, ok := uid.(string); ok && uidStr != "" {
    48→			hasUID = true
    49→		}
    50→	}
    51→
    52→	hasType := false
    53→	if typ, exists := dsRef["type"]; exists {
    54→		if typStr, ok := typ.(string); ok && typStr != "" {
    55→			hasType = true
    56→		}
    57→	}
    58→
    59→	return hasUID || hasType
    60→}
    61→
    62→// MigrateDatasourceNameToRef converts a datasource name/uid string to a reference object
    63→// Matches the frontend migrateDatasourceNameToRef function in DashboardMigrator.ts
    64→// Options:
    65→//   - returnDefaultAsNull: if true, returns nil for "default" datasources (used in V33)
    66→//   - returnDefaultAsNull: if false, returns reference for "default" datasources (used in V36)
    67→func MigrateDatasourceNameToRef(nameOrRef interface{}, options map[string]bool, datasources []DataSourceInfo) map[string]interface{} {
    68→	if options["returnDefaultAsNull"] && (nameOrRef == nil || nameOrRef == "default") {
    69→		return nil
    70→	}
    71→
    72→	// Frontend: if (isDataSourceRef(nameOrRef)) { return nameOrRef; }
    73→	if isDataSourceRef(nameOrRef) {
    74→		return nameOrRef.(map[string]interface{})
    75→	}
    76→
    77→	// Look up datasource by name/UID
    78→	if nameOrRef == nil || nameOrRef == "default" {
    79→		ds := GetDefaultDSInstanceSettings(datasources)
    80→		if ds != nil {
    81→			return GetDataSourceRef(ds)
    82→		}
    83→	}
    84→
    85→	// Check if it's a string name/UID
    86→	if str, ok := nameOrRef.(string); ok {
    87→		// Handle empty string case
    88→		if str == "" {
    89→			// Empty string should return {} (frontend behavior)
    90→			return map[string]interface{}{}
    91→		}
    92→
    93→		// Search for matching datasource
    94→		for _, ds := range datasources {
    95→			if str == ds.Name || str == ds.UID {
    96→				return GetDataSourceRef(&DataSourceInfo{
    97→					UID:        ds.UID,
    98→					Type:       ds.Type,
    99→					Name:       ds.Name,
   100→					APIVersion: ds.APIVersion,
   101→				})
   102→			}
   103→		}
   104→
   105→		// Unknown datasource name should be preserved as UID-only reference
   106→		return map[string]interface{}{
   107→			"uid": str,
   108→		}
   109→	}
   110→
   111→	return nil
   112→}
